mapper.select:
/* DocRcvMapper.getRequestMobileNoByResNo */
SELECT NVL(MRC.CSTMR_MOBILE_FN || MRC.CSTMR_MOBILE_MN || MRC.CSTMR_MOBILE_RN, MRC.CSTMR_TEL_FN || MRC.CSTMR_TEL_MN || MRC.CSTMR_TEL_RN) AS MOBILE_NO
FROM MCP_REQUEST@DL_MCP MR
   , MCP_REQUEST_CSTMR@DL_MCP MRC
WHERE MR.RES_NO = #{resNo}
  AND MR.REQUEST_KEY = MRC.REQUEST_KEY

/* DocRcvMapper.getContractMobileNoByResNo */
SELECT SUB.SUBSCRIBER_NO AS MOBILE_NO
FROM MSP_REQUEST MR
   , MSP_JUO_SUB_INFO SUB
WHERE MR.RES_NO = #{resNo}
  AND MR.CONTRACT_NUM = SUB.CONTRACT_NUM

mapper.insert:
/* DocRcvMapper.insertDocRcv */

    SELECT LPAD(#{resNo}, 12, '0') || LPAD(NVL(MAX(TARGET_SEQ), 0) + 1, 4, '0') AS DOC_RCV_ID
      FROM NMCP_DOC_RCV@DL_MCP
     WHERE RES_NO = #{resNo}

INSERT INTO NMCP_DOC_RCV@DL_MCP (
    DOC_RCV_ID
    , RES_NO
    , TARGET_SEQ
    , REQUEST_DAY
    , REQUEST_DT
    , WORK_TMPL_ID
    , SMS_TEMPLATE_ID
    , MOBILE_NO
    , CRET_ID
    , CRET_DT
) VALUES (
    #{docRcvId}
    , #{resNo}
    , ( SELECT NVL(MAX(TARGET_SEQ), 0) + 1 AS TARGET_SEQ FROM NMCP_DOC_RCV@DL_MCP WHERE RES_NO = #{resNo} )
    , TO_CHAR(SYSDATE, 'YYYYMMDD')
    , SYSDATE
    , #{workTmplId}
    , #{smsTemplateId}
    , #{mobileNo}
    , #{userId}
    , SYSDATE
)

/* DocRcvMapper.insertDocRcvUrl */
INSERT INTO NMCP_DOC_RCV_URL@DL_MCP (
    RCV_URL_ID
    , DOC_RCV_ID
    , URL
    , STATUS
    , ISSUE_DT
    , EXPIRE_DT
    , CRET_ID
    , CRET_DT
) VALUES (
    #{rcvUrlId}
    , #{docRcvId}
    , #{url}
    , 'A'
    , SYSDATE
    , TO_DATE(#{expireDt}, 'YYYYMMDD') + 1
    , #{userId}
    , SYSDATE
)

/* DocRcvMapper.insertDocRcvUrlOtp */

    SELECT NVL(MAX(SEQ), 0) + 1 FROM NMCP_DOC_RCV_URL_OTP@DL_MCP WHERE RCV_URL_ID = #{rcvUrlId}

INSERT INTO NMCP_DOC_RCV_URL_OTP@DL_MCP (
    RCV_URL_ID
    , SEQ
    , OTP
    , STATUS
    , ISSUE_DT
    , FAIL_CNT
    , CRET_ID
    , CRET_DT
) VALUES (
    #{rcvUrlId}
    , #{seq}
    , #{otp}
    , 'A'
    , SYSDATE
    , 0
    , #{userId}
    , SYSDATE
)

mapper.sql:
WITH DOC_RCV_STATUS AS ( SELECT DOC_RCV_ID , RCV_YN , RCV_DT , PROC_STATUS , PROC_DT FROM NMCP_DOC_RCV_STATUS@DL_MCP STT WHERE DOC_SEQ = ( SELECT MAX(DOC_SEQ) FROM NMCP_DOC_RCV_STATUS@DL_MCP WHERE DOC_RCV_ID = STT.DOC_RCV_ID ) ), DOC_RCV_URL AS ( SELECT RCV_URL_ID , DOC_RCV_ID , URL , STATUS , ISSUE_DT , EXPIRE_DT FROM ( SELECT RCV_URL_ID , DOC_RCV_ID , URL , STATUS , ISSUE_DT , EXPIRE_DT , ROW_NUMBER() OVER(PARTITION BY DOC_RCV_ID ORDER BY ISSUE_DT DESC) AS RN FROM NMCP_DOC_RCV_URL@DL_MCP ) WHERE RN = 1 ) SELECT RCV.DOC_RCV_ID , RCV.RES_NO , RCV.TARGET_SEQ , TO_CHAR(RCV.REQUEST_DT, 'YYYY-MM-DD') AS REQUEST_DAY , TO_CHAR(RCV.REQUEST_DT, 'YYYYMMDDHH24MISS') AS REQUEST_DT , RCV.WORK_TMPL_ID , RCV.SMS_TEMPLATE_ID , COALESCE(SUB.SUB_LINK_NAME, MCRC.CSTMR_NAME) AS CSTMR_NAME , RCV.MOBILE_NO , RCV.SCAN_ID , TMPL.WORK_ID , ( SELECT WORK_NM FROM EMV_SCAN_WORK@DL_MCP WHERE WORK_ID = TMPL.WORK_ID ) AS WORK_NM , TMPL.WORK_TMPL_NM , STT.RCV_YN , DECODE(STT.RCV_YN, 'Y', '접수', '미접수') AS RCV_YN_NM , TO_CHAR(STT.RCV_DT, 'YYYY-MM-DD') AS RCV_DT , STT.PROC_STATUS , FN_GET_CODENM('ORG0081', STT.PROC_STATUS) AS PROC_STATUS_NM , TO_CHAR(STT.PROC_DT, 'YYYY-MM-DD') AS PROC_DT , URL.RCV_URL_ID , URL.URL , URL.STATUS AS URL_STATUS , FN_GET_CODENM('ORG0082', URL.STATUS) AS URL_STATUS_NM , TO_CHAR(URL.ISSUE_DT, 'YYYYMMDDHH24MISS') AS URL_ISSUE_DT , TO_CHAR(URL.EXPIRE_DT, 'YYYYMMDDHH24MISS') AS URL_EXPIRE_DT , USR.USR_NM AS CRET_NM FROM NMCP_DOC_RCV@DL_MCP RCV , NMCP_WORK_TMPL@DL_MCP TMPL , DOC_RCV_STATUS STT , DOC_RCV_URL URL , MSP_REQUEST MR , MSP_JUO_SUB_INFO SUB , MCP_REQUEST@DL_MCP MCR , MCP_REQUEST_CSTMR@DL_MCP MCRC , CMN_USR_MST USR WHERE RCV.WORK_TMPL_ID = TMPL.WORK_TMPL_ID AND RCV.DOC_RCV_ID = STT.DOC_RCV_ID AND RCV.DOC_RCV_ID = URL.DOC_RCV_ID AND RCV.RES_NO = MCR.RES_NO (+) AND MCR.REQUEST_KEY = MCRC.REQUEST_KEY (+) AND RCV.RES_NO = MR.RES_NO (+) AND MR.CONTRACT_NUM = SUB.CONTRACT_NUM (+) AND RCV.CRET_ID = USR.USR_ID (+)
AND RCV.REQUEST_DT BETWEEN TO_DATE(#{searchStartDate}, 'YYYYMMDD') AND TO_DATE(#{searchEndDate}, 'YYYYMMDD') + 1
AND TMPL.WORK_TMPL_NM LIKE '%' || #{workTmplNm} || '%'
AND STT.RCV_YN = #{rcvYn}
AND TMPL.WORK_ID = #{workId}
AND URL.STATUS = #{urlStatus}
AND STT.PROC_STATUS = #{procStatus}
AND SUB.CONTRACT_NUM = #{searchVal}
AND RCV.RES_NO = #{searchVal}
AND RCV.MOBILE_NO = #{searchVal}
AND ( SUB.SUB_LINK_NAME = #{searchVal} OR MCRC.CSTMR_NAME = #{searchVal} )
AND USR.USR_NM = #{searchVal}
ORDER BY REQUEST_DT DESC

mapper.update:
/* DocRcvMapper.verifyDocRcvItems */
UPDATE NMCP_DOC_RCV_ITEM@DL_MCP
   SET STATUS = 'C'
       , AMD_ID = #{userId}
       , AMD_DT = SYSDATE
 WHERE DOC_RCV_ID = #{docRcvId}
   AND ITEM_SEQ IN

    #{itemSeq}

/* DocRcvMapper.updateDocRcvItemsPendingToNotReceived */
UPDATE NMCP_DOC_RCV_ITEM@DL_MCP
   SET STATUS = 'N'
       , AMD_ID = #{userId}
       , AMD_DT = SYSDATE
 WHERE DOC_RCV_ID = #{docRcvId}
   AND STATUS = 'P'

/* DocRcvMapper.updateDocRcvItemsPending */
UPDATE NMCP_DOC_RCV_ITEM@DL_MCP
   SET STATUS = 'P'
       , RCV_DT = NULL
       , AMD_ID = #{userId}
       , AMD_DT = SYSDATE
 WHERE DOC_RCV_ID = #{docRcvId}
   AND ITEM_SEQ IN

    #{itemSeq}

/* DocRcvMapper.updateDocRcvUrlExpire */
UPDATE NMCP_DOC_RCV_URL@DL_MCP
   SET EXPIRE_DT = SYSDATE
       , STATUS = 'E'
       , AMD_ID = #{userId}
       , AMD_DT = SYSDATE
 WHERE RCV_URL_ID = #{rcvUrlId}

mapper.select:
/* DocRcvMapper.getMspScanIdByResNo */
SELECT SUB.SCAN_ID AS scanId
  FROM MSP_REQUEST MR
       , MSP_JUO_SUB_INFO SUB
 WHERE MR.RES_NO = #{resNo}
   AND MR.CONTRACT_NUM = SUB.CONTRACT_NUM

/* DocRcvMapper.getMcpScanIdByResNo */
SELECT SCAN_ID AS scanId
  FROM MCP_REQUEST@DL_MCP
 WHERE RES_NO = #{resNo}

