UPDATE NMCP_DOC_RCV_ITEM_FILE@DL_MCP
   SET MERGE_YN = 'Y'
       , AMD_ID = #{userId}
       , AMD_DT = SYSDATE
 WHERE ITEM_SEQ = #{itemSeq}
   AND FILE_ID = #{fileId}

UPDATE NMCP_DOC_RCV_ITEM_FILE@DL_MCP
SET ITEM_SEQ = #{itemSeqTo}
  , AMD_ID = #{userId}
  , AMD_DT = SYSDATE
WHERE ITEM_SEQ = #{itemSeqFrom}
